using System.Collections.Generic;
using UnityEngine;
using Cinemachine;

/// <summary>
/// Orquestrador central da câmara (Tarefa #21 — responsabilidades separadas
/// por ficheiro, todos como "partial class" da mesma CameraManager):
///
/// - CameraManager.cs (este ficheiro): referências, zonas/prioridades das
///   vcams automáticas, modo manual/cutscene, facing.
/// - CameraManager.Follow.cs: efeitos de seguimento do player (look up,
///   zoom dinâmico, lookahead/offset).
/// - CameraManager.Shake.cs: shake de câmara (hit, morte, Action_ShakeCamera).
/// - CameraManager.Bounds.cs: bounds/blockers e confiner (interseção de áreas).
///
/// API pública (Instance, PushZone/PopZone/SetZone, EnterManualLock/Follow/
/// ExitManual, Shake/ShakeHit, SetBaseBounds/AddBlocker/RemoveBlocker) mantém-se
/// inalterada — esta divisão é só organização interna do código.
/// </summary>
public partial class CameraManager : MonoBehaviour
{
    public static CameraManager Instance { get; private set; }

    public enum ZoneType { Normal, Corridor, Boss }

    [Header("References")]
    [SerializeField] private Transform player;
    [SerializeField] private Rigidbody2D playerRb;
    [SerializeField] private PlayerMotor2D playerMotor;
    [SerializeField] private PlayerInputRouter inputRouter;

    [SerializeField] private CinemachineVirtualCamera vcamNormal;
    [SerializeField] private CinemachineVirtualCamera vcamCorridor;
    [SerializeField] private CinemachineVirtualCamera vcamBoss;
    [SerializeField] private CinemachineVirtualCamera vcamManual;

    [SerializeField] private Transform manualAnchor;

    [Header("Auto Camera Priorities")]
    [SerializeField] private int prioActive = 20;
    [SerializeField] private int prioInactive = 10;
    [SerializeField] private int prioManual = 30;

    // Zone stack
    private readonly List<ZoneType> zoneStack = new();

    // State
    private bool manualMode = false;

    // Facing
    private int facingSign = 1;

    // Cached move (fallback se não tiver inputRouter)
    private Vector2 cachedMoveInput;

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
    }

    private void Start()
    {
        // Auto-captura se não veio no inspector
        if (player != null)
        {
            if (playerRb == null) playerRb = player.GetComponent<Rigidbody2D>();
            if (playerMotor == null) playerMotor = player.GetComponent<PlayerMotor2D>();
            if (inputRouter == null) inputRouter = player.GetComponent<PlayerInputRouter>();

            SetFollows(player);
        }

        SetZone(ZoneType.Normal);
        ApplyAutoPriorities();
        UpdateConfinerBounds();
    }

    private void Update()
    {
        if (player == null) return;

        UpdateFacing();

        if (!manualMode)
        {
            UpdateLookUpHold();
            UpdateAutoCameraParams();
            if (enableDynamicZoom) UpdateDynamicZoom();
        }
    }

    // -------------------- PUBLIC API --------------------

    public void SetPlayer(Transform t)
    {
        player = t;
        playerRb = t != null ? t.GetComponent<Rigidbody2D>() : null;
        playerMotor = t != null ? t.GetComponent<PlayerMotor2D>() : null;
        inputRouter = t != null ? t.GetComponent<PlayerInputRouter>() : null;

        SetFollows(t);
    }

    public void SetMoveInput(Vector2 move)
    {
        // opcional: se quiseres alimentar via PlayerController em vez de referenciar o Router aqui
        cachedMoveInput = move;
    }

    public void PushZone(ZoneType z)
    {
        zoneStack.Add(z);
        ApplyAutoPriorities();
    }

    public void PopZone(ZoneType z)
    {
        int idx = zoneStack.LastIndexOf(z);
        if (idx >= 0) zoneStack.RemoveAt(idx);
        ApplyAutoPriorities();
    }

    public void SetZone(ZoneType z)
    {
        zoneStack.Clear();
        zoneStack.Add(z);
        ApplyAutoPriorities();
    }

    public void EnterManualLock(Vector2 worldPos)
    {
        manualMode = true;
        if (manualAnchor != null) manualAnchor.position = worldPos;

        if (vcamManual != null)
        {
            vcamManual.Follow = manualAnchor;
            vcamManual.Priority = prioManual;
        }

        // baixa prioridades das auto (mas não deixa sem camera se manual falhar)
        vcamNormal.Priority = 0;
        vcamCorridor.Priority = 0;
        vcamBoss.Priority = 0;
    }

    public void EnterManualFollow(Transform target)
    {
        manualMode = true;
        if (vcamManual != null)
        {
            vcamManual.Follow = target;
            vcamManual.Priority = prioManual;
        }

        vcamNormal.Priority = 0;
        vcamCorridor.Priority = 0;
        vcamBoss.Priority = 0;
    }

    public void ExitManual()
    {
        manualMode = false;
        if (vcamManual != null) vcamManual.Priority = 0;
        ApplyAutoPriorities();
    }

    // -------------------- INTERNAL LOGIC --------------------

    private void SetFollows(Transform t)
    {
        if (vcamNormal != null) vcamNormal.Follow = t;
        if (vcamCorridor != null) vcamCorridor.Follow = t;
        if (vcamBoss != null) vcamBoss.Follow = t;
    }

    private void ApplyAutoPriorities()
    {
        if (manualMode) return;

        ZoneType top = GetTopZone();

        vcamNormal.Priority = prioInactive;
        vcamCorridor.Priority = prioInactive;
        vcamBoss.Priority = prioInactive;

        switch (top)
        {
            case ZoneType.Corridor:
                vcamCorridor.Priority = prioActive;
                break;
            case ZoneType.Boss:
                vcamBoss.Priority = prioActive;
                break;
            default:
                vcamNormal.Priority = prioActive;
                break;
        }

        if (vcamManual != null) vcamManual.Priority = 0;
    }

    private ZoneType GetTopZone()
    {
        if (zoneStack.Contains(ZoneType.Boss)) return ZoneType.Boss;
        if (zoneStack.Contains(ZoneType.Corridor)) return ZoneType.Corridor;
        return ZoneType.Normal;
    }

    private CinemachineVirtualCamera GetActiveAutoVcam()
    {
        CinemachineVirtualCamera best = vcamNormal;
        int p = (best != null) ? best.Priority : int.MinValue;

        if (vcamCorridor != null && vcamCorridor.Priority > p) { best = vcamCorridor; p = best.Priority; }
        if (vcamBoss != null && vcamBoss.Priority > p) { best = vcamBoss; p = best.Priority; }

        return best;
    }

    /// <summary>Devolve a vcam realmente activa agora: vcamManual durante uma cutscene (Etapa 6), ou a melhor vcam automática caso contrário.</summary>
    private CinemachineVirtualCamera GetActiveVcam()
    {
        if (manualMode && vcamManual != null) return vcamManual;
        return GetActiveAutoVcam();
    }

    private void UpdateFacing()
    {
        // Preferência: usa facing do motor (mais consistente com o teu gameplay)
        if (playerMotor != null)
        {
            facingSign = playerMotor.FacingSign != 0 ? playerMotor.FacingSign : facingSign;
            return;
        }

        // Fallback: usa velocidade
        if (playerRb == null) return;
        float vx = playerRb.velocity.x;
        if (vx > 0.2f) facingSign = 1;
        else if (vx < -0.2f) facingSign = -1;
    }

    private Vector2 GetMoveInput()
    {
        if (inputRouter != null) return inputRouter.Move;
        return cachedMoveInput;
    }
}
